select dept_cd, dept_nm, dept_parent_cd, join_date, retire_date, use_yn from zzz_dept_info
use_yn = 'Y'
AND dept_parent_cd is not null AND dept_parent_cd <> ''
AND (dept_parent_cd in
#{empDeptAuthItem}
OR dept_cd in
#{empDeptAuthItem}
)
AND dept_cd = #{deptCd}
AND dept_nm LIKE CONCAT('%', #{deptNm}, '%')
order by dept_cd asc
